import React, { useContext, useState } from 'react';
import StaffLayout from '../../components/Layouts/StaffLayout';
import { DataContext } from '../../context/DataContext';
import { AuthContext } from '../../context/AuthContext';
import { calculatePerformanceRating, formatCurrency } from '../../utils/helpers';

const Performance = () => {
  const { tasks, staffList } = useContext(DataContext);
  const { user } = useContext(AuthContext);

  // Lọc task user
  const myTasks = tasks.filter(t => t.assigneeId === user.id || 1); // Mock 1
  const currentUserData = staffList.find(s => s.id === user.id || s.id === 1); // Mock data

  const [timeFilter, setTimeFilter] = useState('month'); // day, week, month, year

  // Yêu cầu 9: Tính thu nhập (Giả lập logic)
  const calculateIncome = () => {
      if (!currentUserData) return 0;
      // Công thức ví dụ: Remuneration * (UBI1 + UBI2)% * (số task hoàn thành / tổng task)
      // Trong thực tế sẽ phức tạp hơn theo timeFilter
      const base = currentUserData.remuneration;
      const percent = (currentUserData.ubi1_percent + currentUserData.ubi2_percent) / 100;
      return base + (base * percent);
  };

  return (
    <StaffLayout>
      <div className="p-4 space-y-6">
        <h2 className="text-2xl font-bold">Hiệu suất làm việc</h2>

        {/* Yêu cầu 8: Tổng quan đánh giá */}
        <div className="bg-white p-4 rounded shadow">
            <h3 className="font-bold text-lg mb-4 border-b pb-2">Tổng quan Xếp hạng</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {myTasks.map(task => {
                    const rating = calculatePerformanceRating(task.progress, task.deadline);
                    let colorClass = "bg-gray-100";
                    if(rating === "Xuất sắc") colorClass = "bg-purple-100 text-purple-800 border-purple-300";
                    if(rating === "Tốt") colorClass = "bg-green-100 text-green-800 border-green-300";
                    if(rating === "Cần điều chỉnh") colorClass = "bg-yellow-100 text-yellow-800 border-yellow-300";
                    if(rating === "Cảnh cáo") colorClass = "bg-orange-100 text-orange-800 border-orange-300";
                    if(rating === "Kỷ luật") colorClass = "bg-red-100 text-red-800 border-red-300";

                    return (
                        <div key={task.id} className={`p-3 rounded border ${colorClass}`}>
                            <div className="font-bold">{task.title}</div>
                            <div className="text-sm mt-1">Tiến độ: {task.progress}%</div>
                            <div className="font-bold text-lg mt-2 text-right">{rating}</div>
                        </div>
                    );
                })}
            </div>
        </div>

        {/* Yêu cầu 9: Tổng thu nhập */}
        <div className="bg-white p-4 rounded shadow border-t-4 border-green-500">
            <div className="flex justify-between items-center mb-4">
                <h3 className="font-bold text-lg text-green-800">Thu nhập cá nhân</h3>
                <select className="border p-1 rounded" value={timeFilter} onChange={e => setTimeFilter(e.target.value)}>
                    <option value="day">Hôm nay</option>
                    <option value="week">Tuần này</option>
                    <option value="month">Tháng này</option>
                    <option value="year">Năm nay</option>
                </select>
            </div>
            
            <div className="text-center py-6">
                <p className="text-gray-500 mb-2">Tổng thu nhập ước tính ({timeFilter}):</p>
                <p className="text-4xl font-bold text-green-600">{formatCurrency(calculateIncome())}</p>
                <p className="text-xs text-gray-400 mt-2">*Con số bao gồm Lương cứng + UBI 1 + UBI 2 + Thưởng</p>
            </div>
        </div>
      </div>
    </StaffLayout>
  );
};

export default Performance;
